mapper.select:
SELECT
,
zuoye.zuoye_name as zuoyeName,
yonghu.yonghu_name as yonghuName,
yonghu.yonghu_photo as yonghuPhoto,
jiaoshi.jiaoshi_name as jiaoshiName,
jiaoshi.jiaoshi_uuid_number as jiaoshiUuidNumber
FROM zuoye_submit a
LEFT JOIN zuoye zuoye ON a.zuoye_id = zuoye.id
LEFT JOIN yonghu yonghu ON a.yonghu_id = yonghu.id
LEFT JOIN jiaoshi jiaoshi ON zuoye.jiaoshi_id = jiaoshi.id


        and a.id in

            #{item}



        and a.zuoye_id = #{params.zuoyeId}


        and zuoye.zuoye_name like CONCAT('%',#{params.zuoyeName},'%')


        and a.yonghu_id = #{params.yonghuId}


        and jiaoshi.id = #{params.jiaoshiId}


        and yonghu.yonghu_name like CONCAT('%',#{params.yonghuName},'%')


        and a.submit_content like CONCAT('%',#{params.submitContent},'%')


        and a.submit_status = #{params.submitStatus}


         and a.submit_delete >= #{params.submitDeleteStart} 


         and a.submit_delete <= #{params.submitDeleteEnd} 


        and a.submit_delete = #{params.submitDelete}


order by a.${params.sort} ${params.order}
